ALTER TABLE public.explicacoes_artigos_fila DROP CONSTRAINT IF EXISTS explicacoes_artigos_fila_status_check; ALTER TABLE public.explicacoes_artigos_fila ADD CONSTRAINT explicacoes_artigos_fila_status_check CHECK (status = ANY (ARRAY['pendente','gerando','concluido','erro','pausado'])); UPDATE public.explicacoes_artigos_fila SET status = 'pendente', erro = NULL WHERE status = 'erro';